/**
 * Computes the square-root of the weight matrix.
 *
 * @param m Symmetric, positive-definite (weight) matrix.
 * @return the square-root of the weight matrix.
 */
private RealMatrix squareRoot(RealMatrix m) {
    // Check if the matrix is a diagonal matrix to avoid expensive eigen decomposition
    if (m instanceof DiagonalMatrix) {
        // For diagonal matrices, compute square root of diagonal elements only (O(N) memory)
        final DiagonalMatrix diagMatrix = (DiagonalMatrix) m;
        final int dim = diagMatrix.getRowDimension();
        final double[] diagData = new double[dim];

        for (int i = 0; i < dim; i++) {
            // Take square root of each diagonal element
            diagData[i] = FastMath.sqrt(diagMatrix.getEntry(i, i));
        }

        return new DiagonalMatrix(diagData);
    } else {
        // For non-diagonal matrices, use the original eigen decomposition method
        final EigenDecomposition dec = new EigenDecomposition(m);
        return dec.getSquareRoot();
    }
}

